// ═══════════════════════════════════════════════════════════════════════════════
// EXECUTE UPDATES
// ═══════════════════════════════════════════════════════════════════════════════

// --- Update tools.json ---
const toolsData = readJson('tools.json');
const existingToolSlugs = new Set(toolsData.tools.map(t => t.slug));
const existingToolNames = new Set(toolsData.tools.map(t => t.name.toLowerCase()));

// Find highest numeric ID
let maxId = 0;
toolsData.tools.forEach(t => {
  const n = parseInt(t.id);
  if (!isNaN(n) && n > maxId) maxId = n;
});

let addedTools = 0;
newTools.forEach(tool => {
  const toolSlug = slug(tool.name);
  if (existingToolSlugs.has(toolSlug) || existingToolNames.has(tool.name.toLowerCase())) {
    console.log(`  SKIP tool (exists): ${tool.name}`);
    return;
  }
  maxId++;
  toolsData.tools.push({
    id: String(maxId),
    name: tool.name,
    slug: toolSlug,
    category: tool.category,
    freeTier: tool.freeTier,
    description: tool.description,
    websiteURL: tool.websiteURL,
    tags: tool.tags,
    logo: `/logos/${toolSlug}.svg`,
  });
  existingToolSlugs.add(toolSlug);
  existingToolNames.add(tool.name.toLowerCase());
  addedTools++;
  console.log(`  + Tool: ${tool.name}`);
});
writeJson('tools.json', toolsData);
console.log(`\nTools added: ${addedTools}/${newTools.length}`);

// --- Update prompts.json ---
const promptsRaw = readJson('prompts.json');
const promptsArr = Array.isArray(promptsRaw) ? promptsRaw : promptsRaw.prompts;
const existingPromptSlugs = new Set(promptsArr.map(p => p.slug));

let maxPromptId = 0;
promptsArr.forEach(p => {
  const n = parseInt(p.id);
  if (!isNaN(n) && n > maxPromptId) maxPromptId = n;
});

let addedPrompts = 0;
newPrompts.forEach(prompt => {
  const pSlug = slug(prompt.title);
  if (existingPromptSlugs.has(pSlug)) {
    console.log(`  SKIP prompt (exists): ${prompt.title}`);
    return;
  }
  maxPromptId++;
  promptsArr.push({
    id: String(maxPromptId),
    title: prompt.title,
    slug: pSlug,
    category: prompt.category,
    description: prompt.description,
    promptText: prompt.promptText,
    outputType: prompt.outputType,
    bestFor: prompt.bestFor,
  });
  existingPromptSlugs.add(pSlug);
  addedPrompts++;
  console.log(`  + Prompt: ${prompt.title}`);
});

const promptsOutput = Array.isArray(promptsRaw) ? promptsArr : { ...promptsRaw, prompts: promptsArr };
writeJson('prompts.json', promptsOutput);
console.log(`\nPrompts added: ${addedPrompts}/${newPrompts.length}`);

// --- Update blog.json ---
const blogsData = readJson('blog.json');
const existingBlogSlugs = new Set(blogsData.blogs.map(b => b.slug));

let maxBlogId = 0;
blogsData.blogs.forEach(b => {
  const n = parseInt(b.id);
  if (!isNaN(n) && n > maxBlogId) maxBlogId = n;
});

let addedBlogs = 0;
newBlogs.forEach(blog => {
  if (existingBlogSlugs.has(blog.slug)) {
    console.log(`  SKIP blog (exists): ${blog.title}`);
    return;
  }
  maxBlogId++;
  blogsData.blogs.push({ id: String(maxBlogId), ...blog });
  existingBlogSlugs.add(blog.slug);
  addedBlogs++;
  console.log(`  + Blog: ${blog.title}`);
});
writeJson('blog.json', blogsData);
console.log(`\nBlogs added: ${addedBlogs}/${newBlogs.length}`);

console.log('\n✅ All content updated successfully!');
console.log(`   Tools: +${addedTools} | Prompts: +${addedPrompts} | Blogs: +${addedBlogs}`);
